param([string]$BaseUrl='http://localhost:18081',[string]$BackendUrl='http://localhost:18080')
Set-StrictMode -Version Latest;$ErrorActionPreference='Stop';$repo=[IO.Path]::GetFullPath((Join-Path $PSScriptRoot '..\..'));$demo=Join-Path $repo 'scripts\demo-local.ps1'
& $demo -Action Status;if($LASTEXITCODE-eq 0){'APPLICATION_STARTED_BY_GENERATOR=false';exit 0};& $demo -Action Start;if($LASTEXITCODE-ne 0){throw 'No se pudo iniciar la demo local.'};$d=(Get-Date).AddMinutes(5);do{try{$r=Invoke-RestMethod "$BackendUrl/actuator/health/readiness" -TimeoutSec 5;$f=Invoke-WebRequest $BaseUrl -UseBasicParsing -TimeoutSec 5;if($r.status-eq'UP'-and$f.StatusCode-eq 200){'APPLICATION_STARTED_BY_GENERATOR=true';exit 0}}catch{};Start-Sleep 2}while((Get-Date)-lt$d);throw 'La demo no quedó disponible.'